arguments.command:
# Use nm to get sorted symbols, then find function containing each address
nm -C --defined-only --print-size /tmp/symbols/_.debug 2>/dev/null | grep -i " [tT] " | sort | awk '
BEGIN {
    target[1] = 0x2f4b20
    target[2] = 0x2f4c84
    target[3] = 0x2c1a40
    target[4] = 0x16de04
    ntargets = 4
}
{
    addr = strtonum("0x" $1)
    size = strtonum("0x" $2)
    name = $4
    for (i = 1; i <= ntargets; i++) {
        if (target[i] >= addr && target[i] < addr + size) {
            printf "0x%x => %s (base=0x%x, offset=+0x%x)\n", target[i], name, addr, target[i]-addr
        }
    }
}' 2>/dev/null

