arguments.command:
# Find nearest preceding function symbol for each address
nm -C --defined-only /tmp/symbols/_.debug 2>/dev/null | grep -i " [tT] " | sort | awk '
{
    addr = strtonum("0x" $1)
    name = $3
    addrs[NR] = addr
    names[NR] = name
    count = NR
}
END {
    targets[1] = 0x2f4b20
    targets[2] = 0x2f4c84
    for (t = 1; t <= 2; t++) {
        best_addr = 0
        best_name = "??"
        for (i = 1; i <= count; i++) {
            if (addrs[i] <= targets[t] && addrs[i] > best_addr) {
                best_addr = addrs[i]
                best_name = names[i]
            }
        }
        printf "0x%x => %s (base=0x%x, offset=+0x%x)\n", targets[t], best_name, best_addr, targets[t]-best_addr
    }
}' 2>/dev/null

